  const printExecutiveHistory=()=>{const printWindow=window.open("","_blank","width=1100,height=820");if(!printWindow){onMessage("履歴PDF画面を開けませんでした。ポップアップ許可を確認してください。");return;}const historyRows=executiveHistory.reports.map(report=>`<tr><td>${escapeHtml(report.weekKey)}</td><td>${escapeHtml(report.alertStatus.toUpperCase())} / ${report.riskScore}</td><td>${report.summary.readRate}%</td><td>${report.summary.read}/${report.summary.total}</td><td>${report.summary.proxyRead}</td><td>${report.summary.unread}</td><td>${report.summary.unresolved}</td><td>${report.summary.escalated}</td></tr>`).join("");const recipientRows=(currentExecutiveReport?.recipients??[]).map(recipient=>`<tr><td>${escapeHtml(recipient.email)}</td><td>${escapeHtml(recipient.status==="read"?"本人既読":recipient.status==="proxy_read"?"代理確認":recipient.status==="unresolved"?"配信先未解決":"未読")}</td><td>${recipient.readAt?escapeHtml(new Date(recipient.readAt).toLocaleString("ja-JP")):"—"}</td><td>${recipient.readByEmail?escapeHtml(recipient.readByEmail):"—"}</td><td>${recipient.maximumReminderEscalationLevel}</td></tr>`).join("");const title="経営レポート 配信・既読履歴";printWindow.document.open();printWindow.document.write(`<!doctype html><html lang="ja"><head><meta charset="utf-8"><title>${title}</title><style>@page{size:A4 landscape;margin:13mm}*{box-sizing:border-box}body{margin:0;color:#17243a;font-family:-apple-system,BlinkMacSystemFont,"Segoe UI","Noto Sans JP",sans-serif}header{display:flex;justify-content:space-between;gap:18px;padding:16px 18px;border-radius:12px;background:#101b2e;color:#fff}header h1{margin:0;font-size:20px}header p{margin:5px 0 0;color:#a8bad1;font-size:11px}.score{font-size:28px;font-weight:900}.summary{display:grid;grid-template-columns:repeat(5,1fr);gap:7px;margin:12px 0}.summary span{padding:9px;border:1px solid #dce4ee;border-radius:8px;background:#f6f8fb;font-size:10px}.summary b{display:block;font-size:17px}h2{margin:15px 0 6px;font-size:13px}table{width:100%;border-collapse:collapse;font-size:9px}th,td{padding:6px;border:1px solid #d7e0ea;text-align:left}th{background:#eaf0f7}footer{margin-top:12px;color:#6f7e91;font-size:8px}@media print{body{-webkit-print-color-adjust:exact;print-color-adjust:exact}}</style></head><body><header><div><h1>${title}</h1><p>直近8週 / ${escapeHtml(executiveOperations.schedule)} / 24・48・72時間 自動督促</p></div><div class="score">${executiveHistory.currentReadRate}%</div></header><div class="summary"><span><b>${executiveHistory.averageReadRate}%</b>平均既読率</span><span><b>${executiveHistory.readTotal}</b>既読</span><span><b>${executiveHistory.proxyReadTotal}</b>代理確認</span><span><b>${executiveHistory.unreadTotal}</b>未読</span><span><b>${executiveHistory.unresolvedTotal}</b>未解決</span></div><h2>週別配信履歴</h2><table><thead><tr><th>対象週</th><th>判定</th><th>既読率</th><th>既読/配信</th><th>代理</th><th>未読</th><th>未解決</th><th>LEVEL 3</th></tr></thead><tbody>${historyRows}</tbody></table><h2>最新週 ${escapeHtml(currentExecutiveReport?.weekKey??"—")} 配信先</h2><table><thead><tr><th>配信先</th><th>状態</th><th>確認時刻</th><th>確認者</th><th>LEVEL</th></tr></thead><tbody>${recipientRows}</tbody></table><footer>Generated by Lip Knots Crew v5.6</footer><script>window.addEventListener("load",()=>{window.print();});<\/script></body></html>`);printWindow.document.close();onMessage("配信・既読履歴を開きました。「PDFとして保存」を選んでください。");};
  const printExecutiveDecisionTasks=()=>{const printWindow=window.open("","_blank","width=1100,height=820");if(!printWindow){onMessage("タスクPDF画面を開けませんでした。ポップアップ許可を確認してください。");return;}const rows=decisionTaskBoard.tasks.map(task=>`<tr><td>${escapeHtml(task.weekKey)}</td><td>${escapeHtml(task.priority.toUpperCase())}</td><td>${escapeHtml(task.status==="completed"?"完了":task.status==="in_progress"?"進行中":"未着手")}</td><td>${escapeHtml(task.ownerEmail??"未設定")}</td><td>${task.dueAt?escapeHtml(new Date(task.dueAt).toLocaleString("ja-JP")):"—"}</td><td>${escapeHtml(task.deadline.label)}</td><td>${escapeHtml(task.title)}</td><td>${escapeHtml(task.completionNote??task.progressNote??"—")}</td></tr>`).join("");const title="経営判断タスク 期限・完了統制";const summary=decisionTaskBoard.summary;printWindow.document.open();printWindow.document.write(`<!doctype html><html lang="ja"><head><meta charset="utf-8"><title>${title}</title><style>@page{size:A4 landscape;margin:12mm}*{box-sizing:border-box}body{margin:0;color:#17243a;font-family:-apple-system,BlinkMacSystemFont,"Segoe UI","Noto Sans JP",sans-serif}header{display:flex;justify-content:space-between;padding:15px 18px;border-radius:12px;background:#101b2e;color:#fff}h1{margin:0;font-size:19px}header p{margin:4px 0 0;color:#a8bad1;font-size:10px}.score{font-size:28px;font-weight:900}.summary{display:grid;grid-template-columns:repeat(6,1fr);gap:6px;margin:11px 0}.summary span{padding:8px;border:1px solid #dce4ee;border-radius:8px;background:#f6f8fb;font-size:9px}.summary b{display:block;font-size:16px}table{width:100%;border-collapse:collapse;font-size:8px}th,td{padding:5px;border:1px solid #d7e0ea;text-align:left;vertical-align:top}th{background:#eaf0f7}footer{margin-top:10px;color:#6f7e91;font-size:8px}@media print{body{-webkit-print-color-adjust:exact;print-color-adjust:exact}}</style></head><body><header><div><h1>${title}</h1><p>直近8週 / 担当・期限・進行・完了・LEVEL 1〜3 自動統制</p></div><div class="score">${summary.completionRate}%</div></header><div class="summary"><span><b>${summary.total}</b>総数</span><span><b>${summary.completed}</b>完了</span><span><b>${summary.inProgress}</b>進行中</span><span><b>${summary.open}</b>未着手</span><span><b>${summary.overdue}</b>期限超過</span><span><b>${summary.escalated}</b>LEVEL 3</span></div><table><thead><tr><th>対象週</th><th>優先度</th><th>状態</th><th>担当</th><th>期限</th><th>期限判定</th><th>判断タスク</th><th>進捗・完了証跡</th></tr></thead><tbody>${rows}</tbody></table><footer>Generated by Lip Knots Crew v5.6</footer><script>window.addEventListener("load",()=>{window.print();});<\/script></body></html>`);printWindow.document.close();onMessage("経営判断タスク台帳を開きました。「PDFとして保存」を選んでください。");};
  const printExecutiveOutcomes=()=>{const printWindow=window.open("","_blank","width=1200,height=840");if(!printWindow){onMessage("成果PDF画面を開けませんでした。ポップアップ許可を確認してください。");return;}const completed=decisionTaskBoard.tasks.filter(task=>task.status==="completed");const rows=completed.map(task=>{const outcome=task.outcome??demoUnmeasuredOutcome;return`<tr><td>${escapeHtml(task.weekKey)}</td><td>${escapeHtml(task.title)}</td><td>${escapeHtml(outcome.metricName??"未入力")}</td><td>${outcome.baselineValue??"—"} → ${outcome.targetValue??"—"} → ${outcome.actualValue??"—"} ${escapeHtml(outcome.unit??"")}</td><td>${outcome.improvementRate}%</td><td>${outcome.targetAchievementRate}%</td><td>${yen(outcome.investmentYen)}</td><td>${yen(outcome.benefitYen)}</td><td>${yen(outcome.netBenefitYen)}</td><td>${outcome.roiPercent===null?"—":`${outcome.roiPercent}%`}</td><td>${outcome.score}</td><td>${escapeHtml(outcome.label)}</td></tr>`;}).join("");const summary=decisionTaskBoard.summary;const title="経営判断 成果KPI・改善効果・ROI";printWindow.document.open();printWindow.document.write(`<!doctype html><html lang="ja"><head><meta charset="utf-8"><title>${title}</title><style>@page{size:A4 landscape;margin:10mm}*{box-sizing:border-box}body{margin:0;color:#17243a;font-family:-apple-system,BlinkMacSystemFont,"Segoe UI","Noto Sans JP",sans-serif}header{display:flex;justify-content:space-between;padding:15px 18px;border-radius:12px;background:linear-gradient(135deg,#111b31,#153e4a);color:#fff}h1{margin:0;font-size:18px}header p{margin:4px 0 0;color:#b7d7db;font-size:10px}.score{font-size:28px;font-weight:900}.summary{display:grid;grid-template-columns:repeat(6,1fr);gap:6px;margin:10px 0}.summary span{padding:8px;border:1px solid #d4e3e5;border-radius:8px;background:#f2f8f8;font-size:8px}.summary b{display:block;font-size:15px}table{width:100%;border-collapse:collapse;font-size:7px}th,td{padding:4px;border:1px solid #d7e0ea;text-align:left;vertical-align:top}th{background:#e5f0f1}footer{margin-top:9px;color:#6f7e91;font-size:8px}@media print{body{-webkit-print-color-adjust:exact;print-color-adjust:exact}}</style></head><body><header><div><h1>${title}</h1><p>実行前 → 目標 → 実績 / 改善率 / 目標達成率 / 効果額 / ROI / 100点自動採点</p></div><div class="score">${summary.averageOutcomeScore}</div></header><div class="summary"><span><b>${summary.outcomeMeasurementRate}%</b>測定率</span><span><b>${summary.effective}/${summary.measured}</b>効果あり</span><span><b>${yen(summary.totalInvestmentYen)}</b>投資</span><span><b>${yen(summary.totalBenefitYen)}</b>効果</span><span><b>${yen(summary.netBenefitYen)}</b>純効果</span><span><b>${summary.portfolioRoiPercent===null?"—":`${summary.portfolioRoiPercent}%`}</b>ROI</span></div><table><thead><tr><th>週</th><th>判断タスク</th><th>KPI</th><th>基準→目標→実績</th><th>改善率</th><th>達成率</th><th>投資</th><th>効果</th><th>純効果</th><th>ROI</th><th>点</th><th>判定</th></tr></thead><tbody>${rows||`<tr><td colspan="12">成果入力待ち</td></tr>`}</tbody></table><footer>Generated by Lip Knots Crew v5.6 / outcome_v1</footer><script>window.addEventListener("load",()=>{window.print();});<\/script></body></html>`);printWindow.document.close();onMessage("成果KPI・ROI台帳を開きました。「PDFとして保存」を選んでください。");};
